            let right_count = actual_count(right);
            if right_count != node.borrow().right_child_count {
                println!(
                    "Node {} reports {} right children when there are {}",
                    node.borrow().key,
                    node.borrow().right_child_count,
                    right_count
                );
                panic!("Exiting due to errors.");
            }
        }
