use std::cell::RefCell;
use std::cmp::max;
use std::rc::{Rc, Weak};

#[derive(Debug)]
pub struct BOSTree {
    pub root_node: Option<Rc<RefCell<BOSNode>>>,
    pub cmp_function: BOSTreeCmpFunction,
    pub free_function: Option<BOSTreeFreeFunction>,
}

#[derive(Debug)]
pub struct BOSNode {
    pub left_child_count: u32,
    pub right_child_count: u32,
    pub depth: u32,
    pub left_child_node: Option<Rc<RefCell<BOSNode>>>,
    pub right_child_node: Option<Rc<RefCell<BOSNode>>>,
    pub parent_node: Option<Weak<RefCell<BOSNode>>>,
    pub key: String,
    pub data: Option<String>,
    pub weak_ref_count: u8,
    pub weak_ref_node_valid: u8,
}

pub type BOSTreeCmpFunction = fn(&str, &str) -> i32;
pub type BOSTreeFreeFunction = fn(&Rc<RefCell<BOSNode>>);

// Helper functions
fn node_depth(n: &Option<Rc<RefCell<BOSNode>>>) -> u32 {
    match n {
        Some(x) => x.borrow().depth + 1,
        None => 0,
    }
}

fn compute_balance(node: &Rc<RefCell<BOSNode>>) -> i32 {
    let nb = node.borrow();
    let left_depth = match &nb.left_child_node {
        Some(x) => x.borrow().depth as i32 + 1,
        None => 0,
    };
    let right_depth = match &nb.right_child_node {
        Some(x) => x.borrow().depth as i32 + 1,
        None => 0,
    };
    right_depth - left_depth
}

fn update_depth(node: &Rc<RefCell<BOSNode>>) {
    let mut nb = node.borrow_mut();
    let ld = match &nb.left_child_node {
        Some(x) => x.borrow().depth + 1,
        None => 0,
    };
    let rd = match &nb.right_child_node {
        Some(x) => x.borrow().depth + 1,
        None => 0,
    };
    nb.depth = max(ld, rd);
}

fn rc_opt_eq(a: &Option<Rc<RefCell<BOSNode>>>, b: &Rc<RefCell<BOSNode>>) -> bool {
    match a {
        Some(x) => Rc::ptr_eq(x, b),
        None => false,
    }
}

fn parent_of(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    node.borrow().parent_node.as_ref().and_then(|w| w.upgrade())
}

fn is_left_child(parent: &Rc<RefCell<BOSNode>>, child: &Rc<RefCell<BOSNode>>) -> bool {
    rc_opt_eq(&parent.borrow().left_child_node, child)
}

/// Rotate right around P, returning the new subtree root (L).
fn rotate_right(tree: &mut BOSTree, p: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    let l = p.borrow().left_child_node.as_ref().unwrap().clone();

    // Update parent's link to point to L
    let parent_opt = parent_of(p);
    if let Some(parent) = &parent_opt {
        let mut pb = parent.borrow_mut();
        if rc_opt_eq(&pb.left_child_node, p) {
            pb.left_child_node = Some(l.clone());
        } else {
            pb.right_child_node = Some(l.clone());
        }
    } else {
        tree.root_node = Some(l.clone());
    }

    // L's parent becomes P's old parent
    l.borrow_mut().parent_node = p.borrow().parent_node.clone();

    // P's left becomes L's right
    let l_right = l.borrow().right_child_node.clone();
    let l_right_count = l.borrow().right_child_count;
    {
        let mut pb = p.borrow_mut();
        pb.left_child_node = l_right.clone();
        pb.left_child_count = l_right_count;
    }
    if let Some(ref c) = l_right {
        c.borrow_mut().parent_node = Some(Rc::downgrade(p));
    }
    update_depth(p);
    p.borrow_mut().parent_node = Some(Rc::downgrade(&l));

    // L.right = P
    let p_left_count = p.borrow().left_child_count;
    let p_right_count = p.borrow().right_child_count;
    {
        let mut lb = l.borrow_mut();
        lb.right_child_node = Some(p.clone());
        lb.right_child_count = p_left_count + p_right_count + 1;
    }
    update_depth(&l);

    l
}

fn rotate_left(tree: &mut BOSTree, p: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    let r = p.borrow().right_child_node.as_ref().unwrap().clone();

    let parent_opt = parent_of(p);
    if let Some(parent) = &parent_opt {
        let mut pb = parent.borrow_mut();
        if rc_opt_eq(&pb.left_child_node, p) {
            pb.left_child_node = Some(r.clone());
        } else {
            pb.right_child_node = Some(r.clone());
        }
    } else {
        tree.root_node = Some(r.clone());
    }

    r.borrow_mut().parent_node = p.borrow().parent_node.clone();

    let r_left = r.borrow().left_child_node.clone();
    let r_left_count = r.borrow().left_child_count;
    {
        let mut pb = p.borrow_mut();
        pb.right_child_node = r_left.clone();
        pb.right_child_count = r_left_count;
    }
    if let Some(ref c) = r_left {
        c.borrow_mut().parent_node = Some(Rc::downgrade(p));
    }
    update_depth(p);
    p.borrow_mut().parent_node = Some(Rc::downgrade(&r));

    let p_left_count = p.borrow().left_child_count;
    let p_right_count = p.borrow().right_child_count;
    {
        let mut rb = r.borrow_mut();
        rb.left_child_node = Some(p.clone());
        rb.left_child_count = p_left_count + p_right_count + 1;
    }
    update_depth(&r);

    r
}

impl BOSTree {
    pub fn bostree_new(
        cmp_function: BOSTreeCmpFunction,
        free_function: Option<BOSTreeFreeFunction>,
    ) -> Self {
        BOSTree {
            root_node: None,
            cmp_function,
            free_function,
        }
    }

    pub fn bostree_node_count(&self) -> u32 {
        match &self.root_node {
            Some(r) => {
                let rb = r.borrow();
                rb.left_child_count + rb.right_child_count + 1
            }
            None => 0,
        }
    }

    pub fn bostree_insert(&mut self, key: String, data: Option<String>) -> Rc<RefCell<BOSNode>> {
        let new_node = Rc::new(RefCell::new(BOSNode {
            left_child_count: 0,
            right_child_count: 0,
            depth: 0,
            left_child_node: None,
            right_child_node: None,
            parent_node: None,
            key: key.clone(),
            data,
            weak_ref_count: 1,
            weak_ref_node_valid: 1,
        }));

        if self.root_node.is_none() {
            self.root_node = Some(new_node.clone());
            return new_node;
        }

        // Walk down to find insertion point
        let mut current = self.root_node.as_ref().unwrap().clone();
        let parent_node;
        let inserted_left;
        loop {
            let cmp = (self.cmp_function)(&key, &current.borrow().key);
            if cmp < 0 {
                current.borrow_mut().left_child_count += 1;
                let next = current.borrow().left_child_node.clone();
                match next {
                    Some(n) => current = n,
                    None => {
                        current.borrow_mut().left_child_node = Some(new_node.clone());
                        parent_node = current.clone();
                        inserted_left = true;
                        break;
                    }
                }
            } else {
                current.borrow_mut().right_child_count += 1;
                let next = current.borrow().right_child_node.clone();
                match next {
                    Some(n) => current = n,
                    None => {
                        current.borrow_mut().right_child_node = Some(new_node.clone());
                        parent_node = current.clone();
                        inserted_left = false;
                        break;
                    }
                }
            }
        }

        new_node.borrow_mut().parent_node = Some(Rc::downgrade(&parent_node));
        let _ = inserted_left;

        // Check if depth changed: only when parent had no other child
        let has_left = parent_node.borrow().left_child_node.is_some();
        let has_right = parent_node.borrow().right_child_node.is_some();
        if has_left ^ has_right {
            parent_node.borrow_mut().depth += 1;
            let mut current_parent = parent_of(&parent_node);
            while let Some(pn) = current_parent {
                let new_left_depth = match &pn.borrow().left_child_node {
                    Some(x) => x.borrow().depth + 1,
                    None => 0,
                };
                let new_right_depth = match &pn.borrow().right_child_node {
                    Some(x) => x.borrow().depth + 1,
                    None => 0,
                };
                let max_depth = max(new_left_depth, new_right_depth);
                let old_depth = pn.borrow().depth;
                if old_depth != max_depth {
                    pn.borrow_mut().depth = max_depth;
                } else {
                    break;
                }

                // Check AVL balance
                let mut next_parent_node = pn.clone();
                if new_left_depth >= 2 && new_left_depth - 2 == new_right_depth {
                    // Left-right case
                    let left_child = pn.borrow().left_child_node.as_ref().unwrap().clone();
                    if compute_balance(&left_child) > 0 {
                        rotate_left(self, &left_child);
                    }
                    next_parent_node = rotate_right(self, &pn);
                } else if new_right_depth >= 2 && new_left_depth + 2 == new_right_depth {
                    let right_child = pn.borrow().right_child_node.as_ref().unwrap().clone();
                    if compute_balance(&right_child) < 0 {
                        rotate_right(self, &right_child);
                    }
                    next_parent_node = rotate_left(self, &pn);
                }
                current_parent = parent_of(&next_parent_node);
            }
        }

        new_node
    }

    pub fn bostree_remove(&mut self, node: &Rc<RefCell<BOSNode>>) {
        let bubble_up: Option<Rc<RefCell<BOSNode>>>;

        let has_left = node.borrow().left_child_node.is_some();
        let has_right = node.borrow().right_child_node.is_some();

        if has_left && has_right {
            // Find candidate
            let left_depth = node.borrow().left_child_node.as_ref().unwrap().borrow().depth;
            let right_depth = node.borrow().right_child_node.as_ref().unwrap().borrow().depth;

            let candidate;
            let lost_child;
            let bubble_start;
            if left_depth >= right_depth {
                node.borrow_mut().left_child_count -= 1;
                let mut cand = node.borrow().left_child_node.as_ref().unwrap().clone();
                loop {
                    let next = cand.borrow().right_child_node.clone();
                    match next {
                        Some(n) => {
                            cand.borrow_mut().right_child_count -= 1;
                            cand = n;
                        }
                        None => break,
                    }
                }
                lost_child = cand.borrow().left_child_node.clone();
                candidate = cand;
            } else {
                node.borrow_mut().right_child_count -= 1;
                let mut cand = node.borrow().right_child_node.as_ref().unwrap().clone();
                loop {
                    let next = cand.borrow().left_child_node.clone();
                    match next {
                        Some(n) => {
                            cand.borrow_mut().left_child_count -= 1;
                            cand = n;
                        }
                        None => break,
                    }
                }
                lost_child = cand.borrow().right_child_node.clone();
                candidate = cand;
            }

            // bubble_start is candidate's parent (must exist)
            bubble_start = parent_of(&candidate).unwrap();
            if is_left_child(&bubble_start, &candidate) {
                bubble_start.borrow_mut().left_child_node = lost_child.clone();
            } else {
                bubble_start.borrow_mut().right_child_node = lost_child.clone();
            }
            if let Some(ref lc) = lost_child {
                lc.borrow_mut().parent_node = Some(Rc::downgrade(&bubble_start));
            }

            // Anchor candidate in node's place
            let node_parent_opt = parent_of(node);
            if let Some(ref np) = node_parent_opt {
                let mut npb = np.borrow_mut();
                if rc_opt_eq(&npb.left_child_node, node) {
                    npb.left_child_node = Some(candidate.clone());
                } else {
                    npb.right_child_node = Some(candidate.clone());
                }
            } else {
                self.root_node = Some(candidate.clone());
            }
            candidate.borrow_mut().parent_node = node.borrow().parent_node.clone();

            let node_left = node.borrow().left_child_node.clone();
            let node_left_count = node.borrow().left_child_count;
            let node_right = node.borrow().right_child_node.clone();
            let node_right_count = node.borrow().right_child_count;
            {
                let mut cb = candidate.borrow_mut();
                cb.left_child_node = node_left.clone();
                cb.left_child_count = node_left_count;
                cb.right_child_node = node_right.clone();
                cb.right_child_count = node_right_count;
            }
            if let Some(ref l) = node_left {
                if !Rc::ptr_eq(l, &candidate) {
                    l.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
                }
            }
            if let Some(ref r) = node_right {
                if !Rc::ptr_eq(r, &candidate) {
                    r.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
                }
            }

            // Rebalance from bubble_start up to candidate (exclusive)
            if !Rc::ptr_eq(&bubble_start, node) {
                let mut cur = bubble_start.clone();
                while !Rc::ptr_eq(&cur, &candidate) {
                    update_depth(&cur);
                    let balance = compute_balance(&cur);
                    let mut next_cur = cur.clone();
                    if balance > 1 {
                        let right_child = cur.borrow().right_child_node.as_ref().unwrap().clone();
                        if compute_balance(&right_child) < 0 {
                            rotate_right(self, &right_child);
                        }
                        next_cur = rotate_left(self, &cur);
                    } else if balance < -1 {
                        let left_child = cur.borrow().left_child_node.as_ref().unwrap().clone();
                        if compute_balance(&left_child) > 0 {
                            rotate_left(self, &left_child);
                        }
                        next_cur = rotate_right(self, &cur);
                    }
                    match parent_of(&next_cur) {
                        Some(p) => cur = p,
                        None => break,
                    }
                }
            }

            // Fixup candidate's depth
            update_depth(&candidate);

            bubble_up = parent_of(&candidate);
            if let Some(ref bu) = bubble_up {
                let mut bub = bu.borrow_mut();
                if rc_opt_eq(&bub.left_child_node, &candidate) {
                    bub.left_child_count -= 1;
                } else {
                    bub.right_child_count -= 1;
                }
            }
        } else {
            // Node has at most one child
            let node_parent_opt = parent_of(node);
            if node_parent_opt.is_none() {
                if has_left {
                    let l = node.borrow().left_child_node.clone();
                    self.root_node = l.clone();
                    if let Some(ref ln) = l {
                        ln.borrow_mut().parent_node = None;
                    }
                } else {
                    let r = node.borrow().right_child_node.clone();
                    self.root_node = r.clone();
                    if let Some(ref rn) = r {
                        rn.borrow_mut().parent_node = None;
                    }
                }
                bubble_up = None;
            } else {
                let np = node_parent_opt.unwrap();
                let (candidate, candidate_count) = if has_right {
                    (
                        node.borrow().right_child_node.clone(),
                        node.borrow().right_child_count,
                    )
                } else if has_left {
                    (
                        node.borrow().left_child_node.clone(),
                        node.borrow().left_child_count,
                    )
                } else {
                    (None, 0)
                };

                if is_left_child(&np, node) {
                    let mut npb = np.borrow_mut();
                    npb.left_child_node = candidate.clone();
                    npb.left_child_count = candidate_count;
                } else {
                    let mut npb = np.borrow_mut();
                    npb.right_child_node = candidate.clone();
                    npb.right_child_count = candidate_count;
                }
                if let Some(ref c) = candidate {
                    c.borrow_mut().parent_node = Some(Rc::downgrade(&np));
                }
                bubble_up = Some(np);
            }
        }

        // Bubble up to root
        let mut bu_opt = bubble_up;
        let mut bubbling_finished = false;
        while let Some(bu) = bu_opt {
            if !bubbling_finished {
                let left_depth = match &bu.borrow().left_child_node {
                    Some(x) => x.borrow().depth + 1,
                    None => 0,
                };
                let right_depth = match &bu.borrow().right_child_node {
                    Some(x) => x.borrow().depth + 1,
                    None => 0,
                };
                let new_depth = max(left_depth, right_depth);
                let old_depth = bu.borrow().depth;
                let depth_changed = new_depth != old_depth;
                bu.borrow_mut().depth = new_depth;

                let balance = compute_balance(&bu);
                let mut new_bu = bu.clone();
                if balance < -1 {
                    let lc = bu.borrow().left_child_node.as_ref().unwrap().clone();
                    if compute_balance(&lc) > 0 {
                        rotate_left(self, &lc);
                    }
                    new_bu = rotate_right(self, &bu);
                } else if balance > 1 {
                    let rc_child = bu.borrow().right_child_node.as_ref().unwrap().clone();
                    if compute_balance(&rc_child) < 0 {
                        rotate_right(self, &rc_child);
                    }
                    new_bu = rotate_left(self, &bu);
                }

                if !depth_changed && Rc::ptr_eq(&new_bu, &bu) {
                    bubbling_finished = true;
                }

                // Update parent's child count
                let parent_opt = parent_of(&new_bu);
                if let Some(p) = &parent_opt {
                    let mut pb = p.borrow_mut();
                    if rc_opt_eq(&pb.left_child_node, &new_bu) {
                        pb.left_child_count -= 1;
                    } else {
                        pb.right_child_count -= 1;
                    }
                }
                bu_opt = parent_opt;
            } else {
                // just decrement child count
                let parent_opt = parent_of(&bu);
                if let Some(p) = &parent_opt {
                    let mut pb = p.borrow_mut();
                    if rc_opt_eq(&pb.left_child_node, &bu) {
                        pb.left_child_count -= 1;
                    } else {
                        pb.right_child_count -= 1;
                    }
                }
                bu_opt = parent_opt;
            }
        }

        node.borrow_mut().weak_ref_node_valid = 0;
        // Detach node
        node.borrow_mut().parent_node = None;
        node.borrow_mut().left_child_node = None;
        node.borrow_mut().right_child_node = None;

        // Weak unref
        let _ = self.bostree_node_weak_unref(node);
    }

    pub fn bostree_node_weak_unref(
        &mut self,
        node: &Rc<RefCell<BOSNode>>,
    ) -> Option<Rc<RefCell<BOSNode>>> {
        let count;
        let valid;
        {
            let mut nb = node.borrow_mut();
            nb.weak_ref_count -= 1;
            count = nb.weak_ref_count;
            valid = nb.weak_ref_node_valid;
        }
        if count == 0 {
            if let Some(ff) = self.free_function {
                ff(node);
            }
            None
        } else if valid != 0 {
            Some(node.clone())
        } else {
            None
        }
    }

    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
        let mut current = self.root_node.clone();
        while let Some(c) = current {
            let cmp = (self.cmp_function)(key, &c.borrow().key);
            if cmp == 0 {
                return Some(c);
            } else if cmp < 0 {
                let next = c.borrow().left_child_node.clone();
                current = next;
            } else {
                let next = c.borrow().right_child_node.clone();
                current = next;
            }
        }
        None
    }

    pub fn bostree_select(&self, index: u32) -> Option<Rc<RefCell<BOSNode>>> {
        let mut idx = index;
        let mut current = self.root_node.clone();
        while let Some(c) = current {
            let lcc = c.borrow().left_child_count;
            if lcc <= idx {
                idx -= lcc;
                if idx == 0 {
                    return Some(c);
                }
                idx -= 1;
                let next = c.borrow().right_child_node.clone();
                current = next;
            } else {
                let next = c.borrow().left_child_node.clone();
                current = next;
            }
        }
        None
    }

    #[cfg(debug_assertions)]
    pub fn bostree_print(&self) {
        // No-op debug print
    }
}

pub fn bostree_node_weak_ref(node: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    {
        let mut nb = node.borrow_mut();
        assert!(nb.weak_ref_count < 127);
        assert!(nb.weak_ref_count > 0);
        nb.weak_ref_count += 1;
    }
    node.clone()
}

pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if node.borrow().right_child_node.is_some() {
        let mut cur = node.borrow().right_child_node.as_ref().unwrap().clone();
        loop {
            let next = cur.borrow().left_child_node.clone();
            match next {
                Some(n) => cur = n,
                None => return Some(cur),
            }
        }
    } else {
        let mut cur = node.clone();
        loop {
            let parent = parent_of(&cur);
            match parent {
                Some(p) => {
                    let is_right = rc_opt_eq(&p.borrow().right_child_node, &cur);
                    if is_right {
                        cur = p;
                    } else {
                        return Some(p);
                    }
                }
                None => return None,
            }
        }
    }
}

pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if node.borrow().left_child_node.is_some() {
        let mut cur = node.borrow().left_child_node.as_ref().unwrap().clone();
        loop {
            let next = cur.borrow().right_child_node.clone();
            match next {
                Some(n) => cur = n,
                None => return Some(cur),
            }
        }
    } else {
        let mut cur = node.clone();
        loop {
            let parent = parent_of(&cur);
            match parent {
                Some(p) => {
                    let is_left = rc_opt_eq(&p.borrow().left_child_node, &cur);
                    if is_left {
                        cur = p;
                    } else {
                        return Some(p);
                    }
                }
                None => return None,
            }
        }
    }
}

pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let mut counter = node.borrow().left_child_count;
    let mut cur = Some(node.clone());
    while let Some(c) = cur {
        let parent = parent_of(&c);
        if let Some(ref p) = parent {
            if rc_opt_eq(&p.borrow().right_child_node, &c) {
                counter += 1 + p.borrow().left_child_count;
            }
        }
        cur = parent;
    }
    counter
}
